import React, { useContext } from 'react';
import * as styles from '../styles/Home.module.scss';
import { LightContext } from './Layout';
import { StaticImage } from 'gatsby';

const ParaDiv = ({children}) => {
  const { light } = useContext(LightContext);
  return (
    <div className={light ? styles.para : styles.paraDark}>
      {children}
    </div>
  )
}

const CenterImg = ({src, alt}) => {
  return (
    <div className={styles.centerCon}>
      <StaticImage src={src} alt={alt ? alt : 'image'} />
    </div>
  )
}

export { ParaDiv, CenterImg };
